/* Per-rail ADC channel is NOT derivable (channel-to-pad mapping). The
 * TODO table below records each rail's unresolved channel; every rail
 * read passes this sentinel until an integrator fills the channel in. */
#define WB_ADC_CHANNEL_UNSET (-1)

/* TODO (channel-to-pad mapping, NOT IMPLEMENTED):
 *   check rail_3v3 -> ADC channel for net +3V3 (test point TP4)
 */

int wb_run_selftest(FILE *out)
{
    fprintf(out, "{");
    fprintf(out, "\"artifact\":\"watchy_v1_bench\",");
    fprintf(out, "\"board_serial\":\"%s\",", wb_read_board_serial());
    fprintf(out, "\"testplan_stamp\":{\"locks\":{\"external-interface\":0,\"firmware-facing\":0},\"series\":\"A\"},");
    fprintf(out, "\"results\":{");

    /* [power-on rails] check rail_3v3 (rail) subject +3V3
     * declared by rail_3v3; derived from (none) */
    {
        const char *cid = "rail_3v3";
        double mv = wb_adc_read_mv(cid, WB_ADC_CHANNEL_UNSET);
        fprintf(out, "\"%s\":{\"unit\":\"V\",\"value\":%.6g}", cid, mv / 1000.0);
    }

    /* [current] check batt_current (current) subject +BATT
     * declared by batt_current; derived from (none) */
    {
        fprintf(out, ",");
        const char *cid = "batt_current";
        wb_enter_state("active");
        double ma = wb_read_current_ma(cid, "+BATT", "active");
        fprintf(out, "\"%s\":{\"state\":\"active\",\"unit\":\"mA\",\"value\":%.6g}", cid, ma);
    }

    /* [buses] check i2c_accel (i2c_scan) subject I2C0
     * declared by i2c_accel; derived from (none) */
    {
        fprintf(out, ",");
        const char *cid = "i2c_accel";
        int addrs[32];
        size_t n = wb_i2c_scan(cid, "I2C0", addrs, 32);
        size_t i;
        fprintf(out, "\"%s\":{\"addrs\":[", cid);
        for (i = 0; i < n; i++)
            fprintf(out, "%s%d", i ? "," : "", addrs[i]);
        fprintf(out, "]}");
    }

    /* [signals] check prog_signal (signal) subject debug.prog
     * declared by prog_signal; derived from (none) */
    {
        fprintf(out, ",");
        const char *cid = "prog_signal";
        double freq = 0.0, duty = 0.0;
        wb_measure_signal(cid, "debug.prog.tx", &freq, &duty);
        fprintf(out, "\"%s\":{\"values\":{", cid);
        fprintf(out, "\"freq\":%.6g", freq);
        fprintf(out, "}}");
    }

    fprintf(out, "}");   /* results */
    fprintf(out, "}\n"); /* record */
    return 0;
}

int main(void)
{
    return wb_run_selftest(stdout);
}
